import { useCampaignManager } from './dungeon-use-campaign-manager';

describe('CampaignStateRegression', () => {
  beforeEach(() => {
    localStorage.clear();
  });

  it('Progression Mission Preserves Hero Vitals', () => {
    const manager = useCampaignManager();
    
    const initialHeroes = [
      { id: 'hero-1', currentBody: 3, currentMind: 2, corpo: 8, mente: 3 }
    ];
    
    manager.saveCampaign(initialHeroes, 2);
    
    const savedData = manager.loadCampaign();
    
    expect(savedData).not.toBeNull();
    expect(savedData?.nextMissionIndex).toBe(2);
    expect(savedData?.heroes?.[0]?.currentBody).toBe(3);
    expect(savedData?.heroes?.[0]?.currentMind).toBe(2);
  });

  it('Replay of Completed Mission Resets Hero Vitals to Max', () => {
    const manager = useCampaignManager();
    
    const initialHeroes = [
      { id: 'hero-1', currentBody: 1, currentMind: 1, corpo: 8, mente: 3 }
    ];
    
    manager.saveCampaign(initialHeroes, 3);
    
    const savedData = manager.loadCampaign();
    const selectedMissionIndex = 1;
    
    const isReplay = selectedMissionIndex < (savedData?.nextMissionIndex ?? 0);
    expect(isReplay).toBe(true);
    
    const bootstrappedHeroes = (savedData?.heroes ?? []).map(hero => {
      if (isReplay) {
        return { ...hero, currentBody: hero.corpo, currentMind: hero.mente };
      }
      return hero;
    });
    
    expect(bootstrappedHeroes?.[0]?.currentBody).toBe(8);
    expect(bootstrappedHeroes?.[0]?.currentMind).toBe(3);
  });

  it('Mission Completion Must Not Auto-Heal Campaign Save', () => {
    const manager = useCampaignManager();
    
    const activeHeroes = [
      { id: 'hero-1', currentBody: 2, currentMind: 1, corpo: 8, mente: 3 }
    ];
    const currentMissionIndex = 2;
    const savedIndex = 2;
    
    const newNextMissionIndex = Math.max(savedIndex, currentMissionIndex + 1);
    manager.saveCampaign(activeHeroes, newNextMissionIndex);
    
    const savedData = manager.loadCampaign();
    
    expect(savedData?.heroes?.[0]?.currentBody).toBe(2);
    expect(savedData?.heroes?.[0]?.currentMind).toBe(1);
    expect(savedData?.nextMissionIndex).toBe(3);
  });

  it('Retreat Save Must Not Auto-Heal Campaign Save', () => {
    const manager = useCampaignManager();
    
    const activeHeroes = [
      { id: 'hero-1', currentBody: 8, currentMind: 3, corpo: 8, mente: 3 },
      { id: 'hero-2', currentBody: 1, currentMind: 1, corpo: 7, mente: 4 }
    ];
    const savedIndex = 3;
    
    manager.saveCampaign(activeHeroes, savedIndex);
    
    const savedData = manager.loadCampaign();
    
    expect(savedData?.heroes?.[1]?.currentBody).toBe(1);
    expect(savedData?.heroes?.[1]?.currentMind).toBe(1);
    expect(savedData?.nextMissionIndex).toBe(3);
  });
});